WITH payload AS (
  SELECT $RISQQ91${"questions":[{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.6","internal_question_no":"08C.006","question_sort_key":8300600.256,"question_text":"Are records maintained of the regular inspection and maintenance of the cargo-securing devices on board the ship?","guide_to_inspection":"Equipment considered to be in poor condition is to be marked and not used. All relevant actions for replacement of such\nequipment are to be taken. The equipment in use should be in good condition and inspected as appropriate, in accordance with\nClass and/or maker’s guidance.\nIt is important that each device used for securing cargo should be marked clearly with its SWL and a batch mark or number,\nwhere that mark can be verified by a test certificate. RightShip recommends that these test certificates be clearly labelled and\nkept in an easily accessible file. A method of correct identification and matching of individual certificates with the cargo-\nsecuring devices should be established on board. Cargo-securing devices without certificates must not be used on board.\nThere should be a procedure in place for removing damaged lashing devices from service. The inspection and maintenance\nschemes of the cargo-securing devices on board the ship shall be carried out as specified in the Cargo Securing Manual.\nRegular inspections and maintenance should be carried out under the responsibility of the Master.\nInspection of cargo-securing devices should include as a minimum:\n> routine visual examinations of components being utilised; and\n> periodic examinations/re-testing as required by the Administration. When required, the cargo securing devices concerned\nshould be subjected to inspections by the Administration.\nThe inspection and maintenance the ship’s cargo-securing devices should be documented. Entries should be made in a record\nbook, which should be kept with the Cargo Securing Manual. This record book should contain the following information:\n> procedures for accepting, maintaining and repairing or rejecting cargo-securing devices; and\n> record of inspections.\nThe record should contain information for the Master regarding inspections and adjustment of securing arrangements during\nthe voyage.\n(MSC.1/Circ.1353/Rev.1, Revised Guidelines for the Preparation of the Cargo Securing Manual, 2014)\nAs with lashings, dunnage material that is part of the ship’s outfit, and is not discarded at the end of a voyage, should be stored\nin a suitably clean and dry storage space, away from any chemicals or other items that might cause damage. At appropriate\nintervals, the dunnage materials should be visually examined to determine whether or not any damage has been sustained.\nDamaged pieces should be discarded. Whenever dunnage materials are brought into use, and when new dunnage is brought on\nboard, the items should be thoroughly inspected for defects and for their suitability for the intended purpose.\nTimber carriers\nAll equipment, lashings, hog wires, uprights, deck fittings etc should be in good condition when taken into use. Routine\ninspections of all loose equipment should be carried out. All moving parts should be lubricated as appropriate, in accordance\nwith the requirements set out in the Cargo Securing Manual.\nUprights and their base-foundations, lashing points and all other fixed equipment should be routinely examined. Any defects,\nsuch as worn or damaged lashing points or wasted or deformed uprights, should be repaired to the satisfaction of classification\nsociety as appropriate. Appropriate inspection and maintenance record sheets should be completed and retain on board.\n(Bliault and North of England, P & I Association, 2007)\nThe cell guides, loose lashing and securing equipment including twist locks should be in good condition and free of excessive\nwear and corrosion. The twist locks, lashing and securing equipment of the same type and number, as specified in the approved\nCargo Securing Manual, should be available on board.\nTwist locks can be rated for different tensile loads up to 20 or 25 tonnes. It is important not to use a mix of twist locks that have\ndifferent strength ratings.\n(A Master’s Guide to: Container Securing, 2012)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":137,"source_page_end":137,"raw_source_text":"Are records maintained of the regular inspection and maintenance of the cargo-securing devices\non board the ship? (V)\nGuide to Inspection\nEquipment considered to be in poor condition is to be marked and not used. All relevant actions for replacement of such\nequipment are to be taken. The equipment in use should be in good condition and inspected as appropriate, in accordance with\nClass and/or maker’s guidance.\nIt is important that each device used for securing cargo should be marked clearly with its SWL and a batch mark or number,\nwhere that mark can be verified by a test certificate. RightShip recommends that these test certificates be clearly labelled and\nkept in an easily accessible file. A method of correct identification and matching of individual certificates with the cargo-\nsecuring devices should be established on board. Cargo-securing devices without certificates must not be used on board.\nThere should be a procedure in place for removing damaged lashing devices from service. The inspection and maintenance\nschemes of the cargo-securing devices on board the ship shall be carried out as specified in the Cargo Securing Manual.\nRegular inspections and maintenance should be carried out under the responsibility of the Master.\nInspection of cargo-securing devices should include as a minimum:\n> routine visual examinations of components being utilised; and\n> periodic examinations/re-testing as required by the Administration. When required, the cargo securing devices concerned\nshould be subjected to inspections by the Administration.\nThe inspection and maintenance the ship’s cargo-securing devices should be documented. Entries should be made in a record\nbook, which should be kept with the Cargo Securing Manual. This record book should contain the following information:\n> procedures for accepting, maintaining and repairing or rejecting cargo-securing devices; and\n> record of inspections.\nThe record should contain information for the Master regarding inspections and adjustment of securing arrangements during\nthe voyage.\n(MSC.1/Circ.1353/Rev.1, Revised Guidelines for the Preparation of the Cargo Securing Manual, 2014)\nAs with lashings, dunnage material that is part of the ship’s outfit, and is not discarded at the end of a voyage, should be stored\nin a suitably clean and dry storage space, away from any chemicals or other items that might cause damage. At appropriate\nintervals, the dunnage materials should be visually examined to determine whether or not any damage has been sustained.\nDamaged pieces should be discarded. Whenever dunnage materials are brought into use, and when new dunnage is brought on\nboard, the items should be thoroughly inspected for defects and for their suitability for the intended purpose.\nTimber carriers\nAll equipment, lashings, hog wires, uprights, deck fittings etc should be in good condition when taken into use. Routine\ninspections of all loose equipment should be carried out. All moving parts should be lubricated as appropriate, in accordance\nwith the requirements set out in the Cargo Securing Manual.\nUprights and their base-foundations, lashing points and all other fixed equipment should be routinely examined. Any defects,\nsuch as worn or damaged lashing points or wasted or deformed uprights, should be repaired to the satisfaction of classification\nsociety as appropriate. Appropriate inspection and maintenance record sheets should be completed and retain on board.\n(Bliault and North of England, P & I Association, 2007)\nThe cell guides, loose lashing and securing equipment including twist locks should be in good condition and free of excessive\nwear and corrosion. The twist locks, lashing and securing equipment of the same type and number, as specified in the approved\nCargo Securing Manual, should be available on board.\nTwist locks can be rated for different tensile loads up to 20 or 25 tonnes. It is important not to use a mix of twist locks that have\ndifferent strength ratings.\n(A Master’s Guide to: Container Securing, 2012)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.7","internal_question_no":"08C.007","question_sort_key":8300700.257,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":137,"source_page_end":137,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.8","internal_question_no":"08C.008","question_sort_key":8300800.258,"question_text":"Is there evidence to show that samples of the timber cargoes are being weighed during loading and what is the actual weight compared to the weight stated by the shipper?","guide_to_inspection":"If deemed necessary, samples of the timber cargo should be weighed during loading and their actual weight should be\ncompared to the weight stated by the shipper, in order to correctly assess the ship’s stability.\n(Code of Safe Practice for Ships Carrying Timber Deck Cargoes, 2012)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":138,"source_page_end":138,"raw_source_text":"Is there evidence to show that samples of the timber cargoes are being weighed during loading\nand what is the actual weight compared to the weight stated by the shipper? (V)\nGuide to Inspection\nIf deemed necessary, samples of the timber cargo should be weighed during loading and their actual weight should be\ncompared to the weight stated by the shipper, in order to correctly assess the ship’s stability.\n(Code of Safe Practice for Ships Carrying Timber Deck Cargoes, 2012)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.9","internal_question_no":"08C.009","question_sort_key":8300900.259,"question_text":"If the vessel is a timber carrier, have up to date lashing plans for each stowage and securing arrangement been incorporated in the Cargo Securing Manual?","guide_to_inspection":"Lashing plan means a sketch or drawing showing the required number and strength of securing items for the timber deck cargo\nto obtain safe stowage and securing of timber deck cargoes.\nIn the Cargo Securing Manual, each stowage and securing arrangement should additionally be documented by a lashing plan\nshowing at least the following:\n> Maximum cargo weight for which the arrangement is designed.\n> Maximum stowage height.\n> Required number and strength of blocking devices and lashings as applicable.\n> Required pretension in lashings.\n> Other cargo properties of importance for the securing arrangement such as friction, rigidity of timber packages, etc.\n> Illustrations of all securing items that might be used; and\n> Any restrictions regarding maximum accelerations, weather criteria, e.g., for non-winter conditions only, restricted sea\nareas, etc.\n(Code of Safe Practice for Ships Carrying Timber Deck Cargoes, 2012)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":138,"source_page_end":138,"raw_source_text":"If the vessel is a timber carrier, have up to date lashing plans for each stowage and securing\narrangement been incorporated in the Cargo Securing Manual? (V)\nGuide to Inspection\nLashing plan means a sketch or drawing showing the required number and strength of securing items for the timber deck cargo\nto obtain safe stowage and securing of timber deck cargoes.\nIn the Cargo Securing Manual, each stowage and securing arrangement should additionally be documented by a lashing plan\nshowing at least the following:\n> Maximum cargo weight for which the arrangement is designed.\n> Maximum stowage height.\n> Required number and strength of blocking devices and lashings as applicable.\n> Required pretension in lashings.\n> Other cargo properties of importance for the securing arrangement such as friction, rigidity of timber packages, etc.\n> Illustrations of all securing items that might be used; and\n> Any restrictions regarding maximum accelerations, weather criteria, e.g., for non-winter conditions only, restricted sea\nareas, etc.\n(Code of Safe Practice for Ships Carrying Timber Deck Cargoes, 2012)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.10","internal_question_no":"08C.010","question_sort_key":8301000.26,"question_text":"If the vessel is a timber carrier, has a lashing plan according to the ship’s Cargo Securing Manual been prepared?","guide_to_inspection":"A lashing plan according to the ship’s Cargo Securing Manual should be prepared and the following calculated:\n> Weight and height of stows per hatch.\n> Number of sections in longitudinal direction per hatch.\n> Required number of pieces of lashing equipment; and\n> Required number of uprights, if applicable.\n(Resolution A.1048 (27), Code of Safe Practice for Ships Carrying Timber Deck Cargoes, 2011)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":138,"source_page_end":138,"raw_source_text":"If the vessel is a timber carrier, has a lashing plan according to the ship’s Cargo Securing Manual\nbeen prepared? (V)\nGuide to Inspection\nA lashing plan according to the ship’s Cargo Securing Manual should be prepared and the following calculated:\n> Weight and height of stows per hatch.\n> Number of sections in longitudinal direction per hatch.\n> Required number of pieces of lashing equipment; and\n> Required number of uprights, if applicable.\n(Resolution A.1048 (27), Code of Safe Practice for Ships Carrying Timber Deck Cargoes, 2011)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.11","internal_question_no":"08C.011","question_sort_key":8301100.261,"question_text":"Is a Class-approved loading computer or programme in use and has its operational accuracy been regularly tested?","guide_to_inspection":"A stability instrument installed on board should cover all stability requirements applicable to the ship. The software is subject\nto approval by the Administration. An operation manual should be provided for the stability instrument. The language in which\nthe stability calculation results are displayed and printed out as well as the operation manual is written should be the same as\nused in the ship’s approved stability booklet. A translation into a language considered appropriate may be required. In case of\nmodifications of the ship which cause alterations in the stability booklet, the specific approval of any original stability calculation\nsoftware is no longer valid. The software should be modified accordingly and re-approved. Any change in software version\nrelated to the stability calculation should be reported to and be approved by the Administration.\nIt is the responsibility of the ship’s Master to check the accuracy of the stability instrument at each annual survey by applying at\nleast one approved test condition. If an Administration’s representative is not present for the stability instrument check, a copy\nof the test condition results obtained by this check should be retained on board as documentation of satisfactory testing for\nthe Administration’s representative’s verification. At each renewal survey this checking for all approved test loading conditions\nshould be done in the presence of the Administration’s representative.\n(Resolution MSC.267 (85), Adoption of the International Code on Intact Stability, 2008)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":138,"source_page_end":138,"raw_source_text":"Is a Class-approved loading computer or programme in use and has its operational accuracy been\nregularly tested? (V)\nGuide to Inspection\nA stability instrument installed on board should cover all stability requirements applicable to the ship. The software is subject\nto approval by the Administration. An operation manual should be provided for the stability instrument. The language in which\nthe stability calculation results are displayed and printed out as well as the operation manual is written should be the same as\nused in the ship’s approved stability booklet. A translation into a language considered appropriate may be required. In case of\nmodifications of the ship which cause alterations in the stability booklet, the specific approval of any original stability calculation\nsoftware is no longer valid. The software should be modified accordingly and re-approved. Any change in software version\nrelated to the stability calculation should be reported to and be approved by the Administration.\nIt is the responsibility of the ship’s Master to check the accuracy of the stability instrument at each annual survey by applying at\nleast one approved test condition. If an Administration’s representative is not present for the stability instrument check, a copy\nof the test condition results obtained by this check should be retained on board as documentation of satisfactory testing for\nthe Administration’s representative’s verification. At each renewal survey this checking for all approved test loading conditions\nshould be done in the presence of the Administration’s representative.\n(Resolution MSC.267 (85), Adoption of the International Code on Intact Stability, 2008)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.12","internal_question_no":"08C.012","question_sort_key":8301200.262,"question_text":"Are officers aware of the strength limits of tank tops, tween decks, hatch covers and weather decks with regards to safe cargo stowage and is this information posted in the ship’s office/ ballast control room?","guide_to_inspection":"The maximum permissible loadings, given in tonnes per square metre (t/m²) for each deck and the tank-top, and the hatch\ncovers should be posted in the Ship’s office. The maximum permissible load figures can be found in the capacity plan, the\nmidship section plan and on-deck plans. This information is also quoted in the ship’s trim and stability booklet and in the Cargo\nSecuring Manual.\nIf the maximum permissible loading is exceeded by cargo units, the deck, ’tween deck or tank-top plating, and the under-deck\nstiffening members will sustain damage.\n(Bliault and North of England P & I Association, 2007) (UK P&I CLUB,\nCarefully to Carry Consolidated Edition 2018, 2018)\nStrength of the inner bottom plating could be deteriorated due to corrosion wastage. The operational parameters and tank top\nstrength(T/m2) of the effected vessels may be updated by the classification society.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":139,"source_page_end":139,"raw_source_text":"Are officers aware of the strength limits of tank tops, tween decks, hatch covers and weather decks with\nregards to safe cargo stowage and is this information posted in the ship’s office/ ballast control room? (V)\nGuide to Inspection\nThe maximum permissible loadings, given in tonnes per square metre (t/m²) for each deck and the tank-top, and the hatch\ncovers should be posted in the Ship’s office. The maximum permissible load figures can be found in the capacity plan, the\nmidship section plan and on-deck plans. This information is also quoted in the ship’s trim and stability booklet and in the Cargo\nSecuring Manual.\nIf the maximum permissible loading is exceeded by cargo units, the deck, ’tween deck or tank-top plating, and the under-deck\nstiffening members will sustain damage.\n(Bliault and North of England P & I Association, 2007) (UK P&I CLUB,\nCarefully to Carry Consolidated Edition 2018, 2018)\nStrength of the inner bottom plating could be deteriorated due to corrosion wastage. The operational parameters and tank top\nstrength(T/m2) of the effected vessels may be updated by the classification society.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.13","internal_question_no":"08C.013","question_sort_key":8301300.263,"question_text":"Have pre-stowage and stowage plans been prepared and completed effectively?","guide_to_inspection":"Consideration must be given to the ship’s stability in advance of loading when planning a voyage. The stability condition should\ninclude the departure as well as arrival condition at discharge ports. The inspector should check that effort has been made to\nidentify the point in the voyage when stability was lowest. The stability analysis should not just amount to a determination of the\nvessel’s GM but must also consider the curve of righting levers (GZ). Both are to be checked for compliance with the criteria.\nThe ship’s condition should be updated regularly by careful consideration of the weight and centres of all deadweight on board.\nTanks’ soundings should be checked regularly. The contents of tanks should be determined from soundings and the calculated\nstability condition is only valid if the tank status remains unchanged.\nThe pre-stowage plan should be prepared prior to vessel’s arrival to load port.\nThe pre-stowage plan shall contain the vessel’s name, voyage number, date, name of loading ports, name of discharging ports,\ndimension of holds, capacity of cranes, total cargo on board, total cargo for each port and the signatures of Chief Officer and\nMaster.\nThe following should be considered when preparing a pre stowage plan:\n> The complete cargo specifications, including description, weight and overall dimensions, special handling instructions,\nhazardous classifications, and deck option.\n> Weight of cargo in relation to permissible load of each decks including tank top; each of the decks has weight limitations.\n> proper weight distribution and load spreading measures to prevent the decks from being overloaded.\n> Securing arrangements for the particular cargo.\n> The intended load and discharge port rotation to avoid shifting of cargo and prevent possible damage as a result of shifting\ncargo.\n> Details of all heavy lifts and out of gauge units, including lifting instructions and the centre of gravity.\n> SWL of ship’s cranes and availability of shore crane at the load port/discharge port if needed.\n> Weight distribution, trim, stability and stress levels throughout the voyage and measures preventing from becoming\nexcessively stiff or tender.\n> Cargo compatibility - incompatible cargoes are not stowed next to one another.\nThe objectives of pre-stowage plan are to minimise broken stowage and to prevent overload of tank top/tween decks and hatch\ncovers.\nThe final stowage plan should include details of the final cargo distribution, the total weight and cube in each compartment and\nthe total weight and cube for each discharge port. The plan will show the location of all heavy lifts and hazardous cargo.\n> Before loading a timber deck cargo: A pre-loading plan according to the ship’s Trim and Stability Book should be done and\nthe following should be calculated and checked:\n> Stowage height.\n> Weight per m².\n> Required amount of water ballast; and\n> Displacement, draught, trim and stability at departure and arrival.\nWhen undertaking stability calculations, variation in displacement, centre of gravity and free surface moments due to the\nfollowing factors should be considered:\n> Absorption of water in timber carried as timber deck cargo according to special instruction, see annex C.\n> Ice accretion, if applicable.\n> Variations in consumables; and\n> Ballast water exchange operations, in accordance with approved procedures.\n(Code of Safe Practice for Ships Carrying Timber Deck Cargoes, 2012)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":139,"source_page_end":139,"raw_source_text":"Have pre-stowage and stowage plans been prepared and completed effectively? (V)\nGuide to Inspection\nConsideration must be given to the ship’s stability in advance of loading when planning a voyage. The stability condition should\ninclude the departure as well as arrival condition at discharge ports. The inspector should check that effort has been made to\nidentify the point in the voyage when stability was lowest. The stability analysis should not just amount to a determination of the\nvessel’s GM but must also consider the curve of righting levers (GZ). Both are to be checked for compliance with the criteria.\nThe ship’s condition should be updated regularly by careful consideration of the weight and centres of all deadweight on board.\nTanks’ soundings should be checked regularly. The contents of tanks should be determined from soundings and the calculated\nstability condition is only valid if the tank status remains unchanged.\nThe pre-stowage plan should be prepared prior to vessel’s arrival to load port.\nThe pre-stowage plan shall contain the vessel’s name, voyage number, date, name of loading ports, name of discharging ports,\ndimension of holds, capacity of cranes, total cargo on board, total cargo for each port and the signatures of Chief Officer and\nMaster.\nThe following should be considered when preparing a pre stowage plan:\n> The complete cargo specifications, including description, weight and overall dimensions, special handling instructions,\nhazardous classifications, and deck option.\n> Weight of cargo in relation to permissible load of each decks including tank top; each of the decks has weight limitations.\n> proper weight distribution and load spreading measures to prevent the decks from being overloaded.\n> Securing arrangements for the particular cargo.\n> The intended load and discharge port rotation to avoid shifting of cargo and prevent possible damage as a result of shifting\ncargo.\n> Details of all heavy lifts and out of gauge units, including lifting instructions and the centre of gravity.\n> SWL of ship’s cranes and availability of shore crane at the load port/discharge port if needed.\n> Weight distribution, trim, stability and stress levels throughout the voyage and measures preventing from becoming\nexcessively stiff or tender.\n> Cargo compatibility - incompatible cargoes are not stowed next to one another.\nThe objectives of pre-stowage plan are to minimise broken stowage and to prevent overload of tank top/tween decks and hatch\ncovers.\nThe final stowage plan should include details of the final cargo distribution, the total weight and cube in each compartment and\nthe total weight and cube for each discharge port. The plan will show the location of all heavy lifts and hazardous cargo.\n> Before loading a timber deck cargo: A pre-loading plan according to the ship’s Trim and Stability Book should be done and\nthe following should be calculated and checked:\n> Stowage height.\n> Weight per m².\n> Required amount of water ballast; and\n> Displacement, draught, trim and stability at departure and arrival.\nWhen undertaking stability calculations, variation in displacement, centre of gravity and free surface moments due to the\nfollowing factors should be considered:\n> Absorption of water in timber carried as timber deck cargo according to special instruction, see annex C.\n> Ice accretion, if applicable.\n> Variations in consumables; and\n> Ballast water exchange operations, in accordance with approved procedures.\n(Code of Safe Practice for Ships Carrying Timber Deck Cargoes, 2012)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.14","internal_question_no":"08C.014","question_sort_key":8301400.264,"question_text":"Is there evidence to show that evaluation of forces acting on the cargo unit have been calculated, and correct cargo-securing devices are being used to secure the cargo to the ship?","guide_to_inspection":"Evaluation of forces acting on cargo units shall be incorporated in the Cargo Securing Manual and contain the following\ninformation:\n> Tables or diagrams giving a broad outline of the accelerations which can be expected in various positions on board the\nship in adverse sea conditions and with a range of applicable metacentric height (GM) values.\n> Examples of the forces acting on typical cargo units when subjected to the accelerations referred to in paragraph 3.2.1\nof MSC/Circ.745 and angles of roll and metacentric height (GM) values above which the forces acting on the cargo units\nexceed the permissible limit for the specified securing arrangements as far as practicable.\n> Examples of how to calculate number and strength of portable securing devices required to counteract the forces referred\nto in 3.2.2 of MSC/Circ.745 as well as safety factors to be used for different types of portable cargo securing devices.\nCalculations may be carried out according to Annex 13 to the CSS Code or methods accepted by the Administration.\n> It is recommended that the designer of a Cargo Securing Manual converts the calculation method used into a form suiting\nthe particular ship, its securing devices and the cargo carried. This form may consist of applicable diagrams, tables, or\ncalculated examples; and\n> Other operational arrangements such as electronic data processing (EDP) or use of a loading computer may be accepted\nas alternatives to the requirements of the above paragraphs 3.2.1 to 3.2.4 of MSC/Circ.745, providing that this system\ncontains the same information.\nIt is important that securing devices meet acceptable functional and strength criteria applicable to the ship and its cargo. It\nis also important that the officers on board are aware of the magnitude and direction of the forces involved and the correct\napplication and limitations of the cargo-securing devices. The crew and other persons employed for the securing of cargoes\nshould be instructed in the correct application and use of the cargo securing devices on board the ship. “Maximum Securing\nLoad (MSL)” is a term used to define the allowable load capacity for a device used to secure cargo.\nTo a ship. “Safe Working Load (SWL)” may be substituted for MSL for securing purposes, provided this is equal to or exceeds the\nstrength defined by MSL.\n(MSC.1/Circ.1353/Rev.1, Revised Guidelines for the Preparation of the Cargo Securing manual, 2014)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":140,"source_page_end":140,"raw_source_text":"Is there evidence to show that evaluation of forces acting on the cargo unit have been calculated,\nand correct cargo-securing devices are being used to secure the cargo to the ship? (V)\nGuide to Inspection\nEvaluation of forces acting on cargo units shall be incorporated in the Cargo Securing Manual and contain the following\ninformation:\n> Tables or diagrams giving a broad outline of the accelerations which can be expected in various positions on board the\nship in adverse sea conditions and with a range of applicable metacentric height (GM) values.\n> Examples of the forces acting on typical cargo units when subjected to the accelerations referred to in paragraph 3.2.1\nof MSC/Circ.745 and angles of roll and metacentric height (GM) values above which the forces acting on the cargo units\nexceed the permissible limit for the specified securing arrangements as far as practicable.\n> Examples of how to calculate number and strength of portable securing devices required to counteract the forces referred\nto in 3.2.2 of MSC/Circ.745 as well as safety factors to be used for different types of portable cargo securing devices.\nCalculations may be carried out according to Annex 13 to the CSS Code or methods accepted by the Administration.\n> It is recommended that the designer of a Cargo Securing Manual converts the calculation method used into a form suiting\nthe particular ship, its securing devices and the cargo carried. This form may consist of applicable diagrams, tables, or\ncalculated examples; and\n> Other operational arrangements such as electronic data processing (EDP) or use of a loading computer may be accepted\nas alternatives to the requirements of the above paragraphs 3.2.1 to 3.2.4 of MSC/Circ.745, providing that this system\ncontains the same information.\nIt is important that securing devices meet acceptable functional and strength criteria applicable to the ship and its cargo. It\nis also important that the officers on board are aware of the magnitude and direction of the forces involved and the correct\napplication and limitations of the cargo-securing devices. The crew and other persons employed for the securing of cargoes\nshould be instructed in the correct application and use of the cargo securing devices on board the ship. “Maximum Securing\nLoad (MSL)” is a term used to define the allowable load capacity for a device used to secure cargo.\nTo a ship. “Safe Working Load (SWL)” may be substituted for MSL for securing purposes, provided this is equal to or exceeds the\nstrength defined by MSL.\n(MSC.1/Circ.1353/Rev.1, Revised Guidelines for the Preparation of the Cargo Securing manual, 2014)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.15","internal_question_no":"08C.015","question_sort_key":8301500.265,"question_text":"Have personnel engaged in cargo securing operations been provided with relevant training and familiarisation?","guide_to_inspection":"RightShip recommends that personnel engaged in cargo securing operations attend a formal training program.\nPersonnel engaged in cargo-securing operations should be trained in the lashing and unlashing of containers as necessary to\ncarry out their duties in a safe manner. This should include the different types of lashing equipment that are expected to be used.\nPersonnel engaged in cargo-securing operations should be trained in the identification and handling of bad order or defective\nsecuring gear in accordance with each ship’s procedures, to ensure damaged gear is segregated for repair and maintenance or\ndisposal.\nPersonnel engaged in cargo-securing operations should be trained to develop the knowledge and mental and physical manual\nhandling skills that they require to do their job safely and efficiently, and to develop general safety awareness to recognise and\navoid potential dangers.\nPersonnel should be trained in safe systems of work. Where personnel are involved in working at heights, they should be trained\nin the use of relevant equipment. Where practical, the use of fall protection equipment should take precedence over fall arrest\nsystems.\nPersonnel who are required to handle thermal cables and/or connect and disconnect temperature control units should be given\ntraining in recognising defective cables, receptacles and plugs.\nPersonnel engaged in containership cargo operations should be familiarise with the ship’s unique characteristics and potential\nhazards arising from such operations necessary to carry out their duties.\n(CSS code, 2011)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":140,"source_page_end":140,"raw_source_text":"Have personnel engaged in cargo securing operations been provided with relevant training and\nfamiliarisation? (V)\nGuide to Inspection\nRightShip recommends that personnel engaged in cargo securing operations attend a formal training program.\nPersonnel engaged in cargo-securing operations should be trained in the lashing and unlashing of containers as necessary to\ncarry out their duties in a safe manner. This should include the different types of lashing equipment that are expected to be used.\nPersonnel engaged in cargo-securing operations should be trained in the identification and handling of bad order or defective\nsecuring gear in accordance with each ship’s procedures, to ensure damaged gear is segregated for repair and maintenance or\ndisposal.\nPersonnel engaged in cargo-securing operations should be trained to develop the knowledge and mental and physical manual\nhandling skills that they require to do their job safely and efficiently, and to develop general safety awareness to recognise and\navoid potential dangers.\nPersonnel should be trained in safe systems of work. Where personnel are involved in working at heights, they should be trained\nin the use of relevant equipment. Where practical, the use of fall protection equipment should take precedence over fall arrest\nsystems.\nPersonnel who are required to handle thermal cables and/or connect and disconnect temperature control units should be given\ntraining in recognising defective cables, receptacles and plugs.\nPersonnel engaged in containership cargo operations should be familiarise with the ship’s unique characteristics and potential\nhazards arising from such operations necessary to carry out their duties.\n(CSS code, 2011)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.16","internal_question_no":"08C.016","question_sort_key":8301600.266,"question_text":"If the vessel is carrying timber deck cargo, are relevant regulations of the applicable Load-Line Convention for stowage and securing of timber as prescribed in the ship’s Cargo Securing Manual being followed?","guide_to_inspection":"A complete stowage of tightly stowed timber will increase the ship’s reserve of buoyancy. A ship with such a stowage of timber\nmay be safely loaded to a deeper draught than would normally be allowed. If the ship does not have a timber load-line, then it\ncannot load deeper than the appropriate load-line or the load port and the voyage.\nThe timber deck cargo must be compactly stowed, lashed and secured. The timber deck cargo must not affect the safe\nnavigation, day to day operation on board the ship and stability of the ship at any stage of the voyage. Due regard must be given\nto additions of weight, such as those due to absorption of water; and to losses of weight, such as those due to consumption of\nfuel and stores.\nThe height of the timber deck cargo above the weather deck on a ship within a seasonal winter zone in winter should not exceed\none third of the extreme breadth of the ship. Otherwise, the height of the timber deck cargo should be restricted so that:\n> Adequate visibility is assured.\n> A safe margin of stability is maintained at all stages of the voyage.\n> Any forward-facing profile does not present overhanging shoulders to a head sea, and\n> The weight of the timber deck cargo does not exceed the designed maximum permissible load on the weather deck and\nhatches.\nDuring the course of the voyage, if there is no convenient passage for the crew on or below the deck of the ship giving safe\nmeans of access from the accommodation to all parts used in the necessary working of the ship, guard lines or rails, not more\nthan 330 mm apart vertically, should be provided on each side of the deck cargo to a height of at least 1 m above the cargo.\nIn addition, a lifeline, preferably wire rope, set up taut with a tightening device should be provided as near as practicable to the\ncentreline of the ship. The stanchion supports to all guardrails or lifelines should be spaced so as to prevent undue sagging.\nWhere the cargo is uneven, a safe walking surface of not less than 600 mm in width should be fitted over the cargo and\neffectively secured beneath, or adjacent to, the lifeline.\n(Code of Safe Practice for Ships Carrying Timber Deck Cargoes, 2012)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":141,"source_page_end":141,"raw_source_text":"If the vessel is carrying timber deck cargo, are relevant regulations of the applicable Load-Line\nConvention for stowage and securing of timber as prescribed in the ship’s Cargo Securing Manual\nbeing followed? (V)\nGuide to Inspection\nA complete stowage of tightly stowed timber will increase the ship’s reserve of buoyancy. A ship with such a stowage of timber\nmay be safely loaded to a deeper draught than would normally be allowed. If the ship does not have a timber load-line, then it\ncannot load deeper than the appropriate load-line or the load port and the voyage.\nThe timber deck cargo must be compactly stowed, lashed and secured. The timber deck cargo must not affect the safe\nnavigation, day to day operation on board the ship and stability of the ship at any stage of the voyage. Due regard must be given\nto additions of weight, such as those due to absorption of water; and to losses of weight, such as those due to consumption of\nfuel and stores.\nThe height of the timber deck cargo above the weather deck on a ship within a seasonal winter zone in winter should not exceed\none third of the extreme breadth of the ship. Otherwise, the height of the timber deck cargo should be restricted so that:\n> Adequate visibility is assured.\n> A safe margin of stability is maintained at all stages of the voyage.\n> Any forward-facing profile does not present overhanging shoulders to a head sea, and\n> The weight of the timber deck cargo does not exceed the designed maximum permissible load on the weather deck and\nhatches.\nDuring the course of the voyage, if there is no convenient passage for the crew on or below the deck of the ship giving safe\nmeans of access from the accommodation to all parts used in the necessary working of the ship, guard lines or rails, not more\nthan 330 mm apart vertically, should be provided on each side of the deck cargo to a height of at least 1 m above the cargo.\nIn addition, a lifeline, preferably wire rope, set up taut with a tightening device should be provided as near as practicable to the\ncentreline of the ship. The stanchion supports to all guardrails or lifelines should be spaced so as to prevent undue sagging.\nWhere the cargo is uneven, a safe walking surface of not less than 600 mm in width should be fitted over the cargo and\neffectively secured beneath, or adjacent to, the lifeline.\n(Code of Safe Practice for Ships Carrying Timber Deck Cargoes, 2012)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.17","internal_question_no":"08C.017","question_sort_key":8301700.267,"question_text":"If the vessel is carrying timber, are instructions for ballast water exchange operations for the intended voyage available in the Ballast Water Management Plan?","guide_to_inspection":"All ballast tanks required for the voyage and included in the stability calculations should be filled before the commencement of\nloading on deck and it should be ensured that free surfaces are eliminated in all tanks intended to be completely full or empty.\nProper instructions for ballast water exchange operations, if applicable for the intended voyage, should be available in the Ballast\nWater Management Plan.\n(Code of Safe Practice for Ships Carrying Timber Deck Cargoes, 2012)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":141,"source_page_end":141,"raw_source_text":"If the vessel is carrying timber, are instructions for ballast water exchange operations for the\nintended voyage available in the Ballast Water Management Plan? (V)\nGuide to Inspection\nAll ballast tanks required for the voyage and included in the stability calculations should be filled before the commencement of\nloading on deck and it should be ensured that free surfaces are eliminated in all tanks intended to be completely full or empty.\nProper instructions for ballast water exchange operations, if applicable for the intended voyage, should be available in the Ballast\nWater Management Plan.\n(Code of Safe Practice for Ships Carrying Timber Deck Cargoes, 2012)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.18","internal_question_no":"08C.018","question_sort_key":8301800.268,"question_text":"Can timber deck cargo be jettisoned into the sea in a controlled manner in an emergency?","guide_to_inspection":"Crew going out on deck in the conditions that would possibly necessitate the need to jettison part or all of a cargo of timber put\nthemselves in danger. Remotely operated jettisoning systems should be considered.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":141,"source_page_end":141,"raw_source_text":"Can timber deck cargo be jettisoned into the sea in a controlled manner in an emergency? (V)\nGuide to Inspection\nCrew going out on deck in the conditions that would possibly necessitate the need to jettison part or all of a cargo of timber put\nthemselves in danger. Remotely operated jettisoning systems should be considered.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.19","internal_question_no":"08C.019","question_sort_key":8301900.269,"question_text":"If the vessel is a non-cellular ship, have the containers been stowed correctly on deck?","guide_to_inspection":"At no time should deck-loaded containers overstress the hatch covers or the hatchway structure. In cases of doubt, details of\nstress limitations should be obtained from the Classification Society.\n(Merchant Shipping Notice No, M.1167 Carriage of Containers and Flats in Ships Not Designed or Modified for the Purpose,\n1985)\n> Containers carried on deck or on hatches of such ships should preferably be stowed in the fore-and-aft direction.\n> Containers should not extend over the ship’s sides. Adequate supports should be provided when containers overhang\nhatches or deck structures.\n> Containers should be stowed and secured so as to permit safe access for personnel in the necessary operation of the ship.\n> Containers should at no time overstress the deck or hatches on which they are stowed.\n> Bottom-tier containers, when not resting on stacking devices, should be stowed on timber of sufficient thickness, arranged\nin such a way as to transfer the stack load evenly on to the structure of the stowage area.\n> When stacking containers, use should be made of locking devices, cones, or similar stacking aids, as appropriate, between\nthem.\n> When stowing containers on deck or hatches, the position and strength of the securing points should be taken into\nconsideration.\n(CSS code, 2011)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":142,"source_page_end":142,"raw_source_text":"If the vessel is a non-cellular ship, have the containers been stowed correctly on deck? (V)\nGuide to Inspection\nAt no time should deck-loaded containers overstress the hatch covers or the hatchway structure. In cases of doubt, details of\nstress limitations should be obtained from the Classification Society.\n(Merchant Shipping Notice No, M.1167 Carriage of Containers and Flats in Ships Not Designed or Modified for the Purpose,\n1985)\n> Containers carried on deck or on hatches of such ships should preferably be stowed in the fore-and-aft direction.\n> Containers should not extend over the ship’s sides. Adequate supports should be provided when containers overhang\nhatches or deck structures.\n> Containers should be stowed and secured so as to permit safe access for personnel in the necessary operation of the ship.\n> Containers should at no time overstress the deck or hatches on which they are stowed.\n> Bottom-tier containers, when not resting on stacking devices, should be stowed on timber of sufficient thickness, arranged\nin such a way as to transfer the stack load evenly on to the structure of the stowage area.\n> When stacking containers, use should be made of locking devices, cones, or similar stacking aids, as appropriate, between\nthem.\n> When stowing containers on deck or hatches, the position and strength of the securing points should be taken into\nconsideration.\n(CSS code, 2011)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.20","internal_question_no":"08C.020","question_sort_key":8302000.27,"question_text":"If refrigerated containers are carried, is there a procedure in place for monitoring their temperature, are records of temperature readings maintained, and are sufficient spare parts available on board?","guide_to_inspection":"Regular monitoring and recording of the temperatures of the reefer containers should be carried out and properly documented.\nIn the event of a claim these can be compared against the reefer unit download data and shipper’s mobile temperature devices.\n(Refrigerated Containers, 2013)\nIn the event of reefer container breakdowns, ships should have adequate spares onboard and the relevant skills to carry out\nemergency repairs to the reefer onboard.\nThe ship should also give prompt notification of reefer problems or malfunctions that cannot be repaired on board.\n(Refrigerated Containers, 2013)\nThe inspector shall record in comments if the reefer containers had been equipped with IoT Device. For additional information,\nreference should be made to the DCSA IoT data standard for remote Reefer container monitoring on board a vessel. Click here.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":142,"source_page_end":142,"raw_source_text":"If refrigerated containers are carried, is there a procedure in place for monitoring their temperature,\nare records of temperature readings maintained, and are sufficient spare parts available on board? (V)\nGuide to Inspection\nRegular monitoring and recording of the temperatures of the reefer containers should be carried out and properly documented.\nIn the event of a claim these can be compared against the reefer unit download data and shipper’s mobile temperature devices.\n(Refrigerated Containers, 2013)\nIn the event of reefer container breakdowns, ships should have adequate spares onboard and the relevant skills to carry out\nemergency repairs to the reefer onboard.\nThe ship should also give prompt notification of reefer problems or malfunctions that cannot be repaired on board.\n(Refrigerated Containers, 2013)\nThe inspector shall record in comments if the reefer containers had been equipped with IoT Device. For additional information,\nreference should be made to the DCSA IoT data standard for remote Reefer container monitoring on board a vessel. Click here.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.21","internal_question_no":"08C.021","question_sort_key":8302100.271,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":142,"source_page_end":142,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.22","internal_question_no":"08C.022","question_sort_key":8302200.272,"question_text":"If refrigerated containers are carried, is the electric power supply permanently installed from the engine room and are the ship’s electrical distribution system and electric container sockets in good condition and undamaged?","guide_to_inspection":"The ship’s electrical distribution system and container supply sockets should be in good working order and undamaged.\n(Refrigerated Containers, 2013)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":142,"source_page_end":142,"raw_source_text":"If refrigerated containers are carried, is the electric power supply permanently installed from the\nengine room and are the ship’s electrical distribution system and electric container sockets in good\ncondition and undamaged? (V)\nGuide to Inspection\nThe ship’s electrical distribution system and container supply sockets should be in good working order and undamaged.\n(Refrigerated Containers, 2013)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.23","internal_question_no":"08C.023","question_sort_key":8302300.273,"question_text":"Are pre-loading/acceptance procedures for the carriage of vehicles on board a ro-ro cargo ship incorporated in the SMS?","guide_to_inspection":"A well-documented pre-loading/acceptance procedure should cover basic checks for the carriage of new and used vehicles.\nThis may include, but not be limited to:\n> Ignition switched off and the key removed to an agreed location. Consideration should be given to keeping the keys inside\nthe vehicle in a visible place to avoid the potential of delays resulting from the loss of keys\n> Disconnection of all battery cables; isolation of battery terminals\n> Inspection of battery for visible signs of damage\n> Prohibiting the carriage of spare/excess fuels or flammable liquids\n> Checking the integrity of seals and pipelines in order to ensure there are no visible leaks - are there visible signs of leaking\noils or fuels? Is the engine bay lagging oil-soaked? Is the engine bay relatively clean?\n> Checking interior to ensure that flammable material such as oily rags spare fuel, undeclared chemicals etc. aren’t stored\ninside a vehicle.\n(Ro-Ro Fires, 2017)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":142,"source_page_end":142,"raw_source_text":"Are pre-loading/acceptance procedures for the carriage of vehicles on board a ro-ro cargo ship\nincorporated in the SMS? (V)\nGuide to Inspection\nA well-documented pre-loading/acceptance procedure should cover basic checks for the carriage of new and used vehicles.\nThis may include, but not be limited to:\n> Ignition switched off and the key removed to an agreed location. Consideration should be given to keeping the keys inside\nthe vehicle in a visible place to avoid the potential of delays resulting from the loss of keys\n> Disconnection of all battery cables; isolation of battery terminals\n> Inspection of battery for visible signs of damage\n> Prohibiting the carriage of spare/excess fuels or flammable liquids\n> Checking the integrity of seals and pipelines in order to ensure there are no visible leaks - are there visible signs of leaking\noils or fuels? Is the engine bay lagging oil-soaked? Is the engine bay relatively clean?\n> Checking interior to ensure that flammable material such as oily rags spare fuel, undeclared chemicals etc. aren’t stored\ninside a vehicle.\n(Ro-Ro Fires, 2017)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.24","internal_question_no":"08C.024","question_sort_key":8302400.274,"question_text":"Is the ro-ro cargo ship equipped with CCTV remote monitoring to monitor the vehicle decks?","guide_to_inspection":"It is vitally important that alarms are treated seriously, and the appropriate action taken to establish the current condition of the\nspace where the alarms have been activated. This may involve the use of CCTV equipment or sending someone to go to the\narea to investigate further. Whilst the use of a lookout offers a valuable first-hand onsite appraisal, it has a number of limitations\nthat should be understood, amongst which are:\n> The time taken to get onsite, especially on large vessels, may add considerable time to a first response for fighting any\npotential fire\n> You may be placing the lookout in a potentially dangerous situation where they may be overcome by smoke or heat\n> It is essential that if using a lookout then they are briefed about the situation and equipped with functioning two-way\ncommunications with the OOW.\n(Ro-Ro Fires, 2017)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":143,"source_page_end":143,"raw_source_text":"Is the ro-ro cargo ship equipped with CCTV remote monitoring to monitor the vehicle decks? (V)\nGuide to Inspection\nIt is vitally important that alarms are treated seriously, and the appropriate action taken to establish the current condition of the\nspace where the alarms have been activated. This may involve the use of CCTV equipment or sending someone to go to the\narea to investigate further. Whilst the use of a lookout offers a valuable first-hand onsite appraisal, it has a number of limitations\nthat should be understood, amongst which are:\n> The time taken to get onsite, especially on large vessels, may add considerable time to a first response for fighting any\npotential fire\n> You may be placing the lookout in a potentially dangerous situation where they may be overcome by smoke or heat\n> It is essential that if using a lookout then they are briefed about the situation and equipped with functioning two-way\ncommunications with the OOW.\n(Ro-Ro Fires, 2017)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.25","internal_question_no":"08C.025","question_sort_key":8302500.275,"question_text":"Is the ro-ro cargo ship drainage system in good order, tested regularly and are effective measures in place to prevent blocking of drains?","guide_to_inspection":"Resolution MSC.256 (84) introduced changes to SOLAS Chapter II-2, Regulation 20 concerning the drainage of fire-fighting\nwater from fixed pressure water-spraying systems within vehicle, special category and ro-ro spaces. For cargo and passenger\nships constructed on or after January 1, 2010, which have vehicle, ro-ro or special category spaces fitted with a fixed pressure\nwater-spraying system, there are requirements for the drainage of the spaces.\nFor closed vehicle and ro-ro spaces and special category spaces, where fixed water-spraying systems are fitted, effective\nmeasures should be in place to ensure floating debris does not block drains in spaces.\n> An easily removable grating, screen or other means should be installed over each drain opening in the protected spaces to\nprevent debris from blocking the drain. The total open area ratio of the grating to the attached drainpipe should be at least\n6 to 1. The grating should be raised above the deck or installed at an angle to prevent large objects from blocking the drain.\nNo dimension of the individual openings in the grating should be more than 25 mm.\n> No grating or screen is required when a fixed mechanical system is provided to unblock the drainage system, or when\nother than a gravity drain system is provided with its own filter.\n> A clearly visible sign or marking should be provided not less than 1,500 mm above each drain opening stating, “Drain\nopening – do not cover or obstruct”. The marking should be in letters at least 50 mm in height.\nIn-service examination requirements:\n> Drainage systems should be visually examined periodically for blockage or other damage. If obstructions are noted, then\nthey should be flushed with hoses to confirm that the system is functional.\n(MSC.1/Circ.1320, Guidelines for the drainage of firefighting water from closed\nvehicle and ro-ro spaces and special category spaces of passenger and cargo ships, 2009)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":143,"source_page_end":143,"raw_source_text":"Is the ro-ro cargo ship drainage system in good order, tested regularly and are effective measures\nin place to prevent blocking of drains? (V)\nGuide to Inspection\nResolution MSC.256 (84) introduced changes to SOLAS Chapter II-2, Regulation 20 concerning the drainage of fire-fighting\nwater from fixed pressure water-spraying systems within vehicle, special category and ro-ro spaces. For cargo and passenger\nships constructed on or after January 1, 2010, which have vehicle, ro-ro or special category spaces fitted with a fixed pressure\nwater-spraying system, there are requirements for the drainage of the spaces.\nFor closed vehicle and ro-ro spaces and special category spaces, where fixed water-spraying systems are fitted, effective\nmeasures should be in place to ensure floating debris does not block drains in spaces.\n> An easily removable grating, screen or other means should be installed over each drain opening in the protected spaces to\nprevent debris from blocking the drain. The total open area ratio of the grating to the attached drainpipe should be at least\n6 to 1. The grating should be raised above the deck or installed at an angle to prevent large objects from blocking the drain.\nNo dimension of the individual openings in the grating should be more than 25 mm.\n> No grating or screen is required when a fixed mechanical system is provided to unblock the drainage system, or when\nother than a gravity drain system is provided with its own filter.\n> A clearly visible sign or marking should be provided not less than 1,500 mm above each drain opening stating, “Drain\nopening – do not cover or obstruct”. The marking should be in letters at least 50 mm in height.\nIn-service examination requirements:\n> Drainage systems should be visually examined periodically for blockage or other damage. If obstructions are noted, then\nthey should be flushed with hoses to confirm that the system is functional.\n(MSC.1/Circ.1320, Guidelines for the drainage of firefighting water from closed\nvehicle and ro-ro spaces and special category spaces of passenger and cargo ships, 2009)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.26","internal_question_no":"08C.026","question_sort_key":8302600.276,"question_text":"Is the ro-ro cargo ship provided with an approved Operating and Maintenance Manual (OMM)?","guide_to_inspection":"The requirement for an Operating and Maintenance Manual (OMM) is applied to shell doors such as bow doors with the\nassociated inner doors, side shell doors and stern doors with respect to the IACS Unified Requirements S8, S9, S15 and S16\nas well as SOLAS 74 as amended. In addition to common operating instructions, the OMM shall provide full information to the\nship’s staff for maintaining and monitoring the sound condition of all elements of the shell door systems, relevant for the safety\nof the vessel. Detailed information on the procedures of maintenance and function tests are to be incorporated in the OMM.\nThe OMM is applicable to:\n> Ro-Ro passenger ships\n> Ro-Ro cargo ships with bow door, and keel laid on or after 01 July 1996, if the bow door/inner door gives access to an\nenclosed superstructure\n> Ro-Ro cargo ships with side or stern door, and keel laid on or after 01 July 1997, if the side or stern door gives access to\nenclosed spaces.\nThe OMM is subject to Class approval. The OMM must be prepared in a language understood by the users. If this language is\nnot English, a translation into English is to be included.\nOperational instructions for the Master: Special safety precautions shall emphasize the importance of closed openings for\ngranting seaworthiness of the vessel. It shall be pointed out that special care must be taken when opening of shell doors at sea\nbecomes necessary e. g. for embarkation of pilots or in case of emergency.\nThe operating panels for the operation of doors are to be inaccessible to unauthorised persons.\n(SOLAS 74, 2020) (IMO A. 793(19) Strength and securing and locking arrangements of shell doors on ro-ro passenger ships, 1995)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":143,"source_page_end":143,"raw_source_text":"Is the ro-ro cargo ship provided with an approved Operating and Maintenance Manual (OMM)? (V)\nGuide to Inspection\nThe requirement for an Operating and Maintenance Manual (OMM) is applied to shell doors such as bow doors with the\nassociated inner doors, side shell doors and stern doors with respect to the IACS Unified Requirements S8, S9, S15 and S16\nas well as SOLAS 74 as amended. In addition to common operating instructions, the OMM shall provide full information to the\nship’s staff for maintaining and monitoring the sound condition of all elements of the shell door systems, relevant for the safety\nof the vessel. Detailed information on the procedures of maintenance and function tests are to be incorporated in the OMM.\nThe OMM is applicable to:\n> Ro-Ro passenger ships\n> Ro-Ro cargo ships with bow door, and keel laid on or after 01 July 1996, if the bow door/inner door gives access to an\nenclosed superstructure\n> Ro-Ro cargo ships with side or stern door, and keel laid on or after 01 July 1997, if the side or stern door gives access to\nenclosed spaces.\nThe OMM is subject to Class approval. The OMM must be prepared in a language understood by the users. If this language is\nnot English, a translation into English is to be included.\nOperational instructions for the Master: Special safety precautions shall emphasize the importance of closed openings for\ngranting seaworthiness of the vessel. It shall be pointed out that special care must be taken when opening of shell doors at sea\nbecomes necessary e. g. for embarkation of pilots or in case of emergency.\nThe operating panels for the operation of doors are to be inaccessible to unauthorised persons.\n(SOLAS 74, 2020) (IMO A. 793(19) Strength and securing and locking arrangements of shell doors on ro-ro passenger ships, 1995)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.27","internal_question_no":"08C.027","question_sort_key":8302700.277,"question_text":"Are procedures in place to carry out function and tightness testing of bow, inner, side shell, stern doors and main to lower deck cargo elevators of ro-ro cargo ships and is there evidence of regular testing?","guide_to_inspection":"In comments, record the date and frequency of function and tightness testing of the doors, and function testing of the indicator\nsystem and tightness test. Also, record the opening and closing time of the doors.\nIt is recommended that recorded inspections of the door supporting and securing devices be carried out by the ship’s staff at\nmonthly intervals or following incidents that could result in damage, including heavy weather or contact in the region of side\nshell and stern doors. Any damage recorded during such inspections is to be reported to the Classification Society.\nMaintenance, function, and tightness tests of the doors shall be incorporated in the PMS system as per manufacturer’s\nrecommendation.\nThe following shall be incorporated in the function test procedures.\nFunction test of the doors:\n> Proper working of the hinging arms and hinges\n> Proper engagement of the thrust bearings\n> Device for locking the door in the open position\n> Securing, supporting and locking devices\n> Proper sequence of the interlock system for the opening/closing system and the securing and locking devices\n> Mechanical lock of the securing devices\n> Proper locking of hydraulic securing devices in the event of a loss of the hydraulic fluid, according to the procedure\nprovided by the OMM\n> Correct indication of open/closed position of doors and securing/locking devices at the navigation bridge and other control\nstations\n> Isolation of the hydraulic securing/locking devices from other hydraulic systems\n> Confirmation that the operating panels are inaccessible to unauthorised persons\n> Verification that a notice plate giving instructions to the effect that all securing devices are to be closed and locked before\nleaving harbour is placed at each operating panel and supplemented by warning indicator lights\n> Examination of electrical equipment for opening, closing and securing the doors.\nFunction test of the indicator system – indicator systems where fitted should be incorporated in the procedure and tested\nregularly:\n> Proper visible indication and audible alarm on the navigation bridge panel, according to the selected function “harbour/sea\nvoyage” and on the operating panel\n> Lamp test function on both panels\n> Verification that it is not possible to turn off the indicator light on both panels\n> Verification of failsafe performance, according to the procedure provided by the OMM\n> Confirmation that power supply for indicator system is supplied by the emergency source or other secure power supply\nand independent of the power supply for operating the doors\n> Proper condition of sensors and protection from water, ice formation and mechanical damage.\nWhere fitted, the water leakage detection system is to be tested, including proper audible alarm on the navigation bridge panel\nand on the engine control room panel, according to the procedure provided by the OMM.\nTightness test: A hose test or equivalent is to be carried out at regular interval.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":144,"source_page_end":144,"raw_source_text":"Are procedures in place to carry out function and tightness testing of bow, inner, side shell, stern doors\nand main to lower deck cargo elevators of ro-ro cargo ships and is there evidence of regular testing? (V)\nGuide to Inspection\nIn comments, record the date and frequency of function and tightness testing of the doors, and function testing of the indicator\nsystem and tightness test. Also, record the opening and closing time of the doors.\nIt is recommended that recorded inspections of the door supporting and securing devices be carried out by the ship’s staff at\nmonthly intervals or following incidents that could result in damage, including heavy weather or contact in the region of side\nshell and stern doors. Any damage recorded during such inspections is to be reported to the Classification Society.\nMaintenance, function, and tightness tests of the doors shall be incorporated in the PMS system as per manufacturer’s\nrecommendation.\nThe following shall be incorporated in the function test procedures.\nFunction test of the doors:\n> Proper working of the hinging arms and hinges\n> Proper engagement of the thrust bearings\n> Device for locking the door in the open position\n> Securing, supporting and locking devices\n> Proper sequence of the interlock system for the opening/closing system and the securing and locking devices\n> Mechanical lock of the securing devices\n> Proper locking of hydraulic securing devices in the event of a loss of the hydraulic fluid, according to the procedure\nprovided by the OMM\n> Correct indication of open/closed position of doors and securing/locking devices at the navigation bridge and other control\nstations\n> Isolation of the hydraulic securing/locking devices from other hydraulic systems\n> Confirmation that the operating panels are inaccessible to unauthorised persons\n> Verification that a notice plate giving instructions to the effect that all securing devices are to be closed and locked before\nleaving harbour is placed at each operating panel and supplemented by warning indicator lights\n> Examination of electrical equipment for opening, closing and securing the doors.\nFunction test of the indicator system – indicator systems where fitted should be incorporated in the procedure and tested\nregularly:\n> Proper visible indication and audible alarm on the navigation bridge panel, according to the selected function “harbour/sea\nvoyage” and on the operating panel\n> Lamp test function on both panels\n> Verification that it is not possible to turn off the indicator light on both panels\n> Verification of failsafe performance, according to the procedure provided by the OMM\n> Confirmation that power supply for indicator system is supplied by the emergency source or other secure power supply\nand independent of the power supply for operating the doors\n> Proper condition of sensors and protection from water, ice formation and mechanical damage.\nWhere fitted, the water leakage detection system is to be tested, including proper audible alarm on the navigation bridge panel\nand on the engine control room panel, according to the procedure provided by the OMM.\nTightness test: A hose test or equivalent is to be carried out at regular interval.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.28","internal_question_no":"08C.028","question_sort_key":8302800.278,"question_text":"Is an operation manual for the ventilation system in a ro-ro cargo space provided and do records on board verify that the air quality is tested?","guide_to_inspection":"Maintenance of the ventilation system shall be incorporated in the PMS system as per manufacturer’s recommendation.\nAn operation manual should be supplied and should include a plan of the ventilation system, showing fans, air supply and\nexhaust air openings and doors, ramps, hatches, etc.\nThe location of the control panel for the ro-ro cargo space ventilation system should also be marked. The plan should show\nthe various options for operation of the ventilation system. It should include details of the air flow design and of the estimated\nnumber of different types of vehicles in the different ro-ro cargo spaces under various loading and unloading conditions.\nThe plan should be periodically revised and/or supplemented on the basis of the experience gained from the normal vehicle\nloading and unloading conditions. A number of blank drawings should therefore be kept on board. On the basis of such\nexperience, it should also be possible to draw up guidelines for the maximum number of vehicles that should be allowed to\noperate simultaneously. Whenever possible, places which are sheltered from the air flow should be indicated on the plans.\nThe operation manual should include guidance for the service and maintenance of the systems.\nShipowners and operators should consider testing the air quality in conjunction with tests of the ventilation system to ensure\nproper maintenance and functioning of the ventilation system. Situations which indicate the necessity to conduct air-quality\nmonitoring include worker complaints (e.g. headache, dizziness, stinging of the eyes or respiratory system), indications that the\nventilation system itself has deteriorated, and changes in vessel operation which are substantially different from that for which\nthe original ventilation system was verified.\n(MSC.1/Circ.1515, Revised design guidelines and operational recommendations for\nventilation systems in ro-ro cargo spaces, 2015)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":145,"source_page_end":145,"raw_source_text":"Is an operation manual for the ventilation system in a ro-ro cargo space provided and do records\non board verify that the air quality is tested? (V)\nGuide to Inspection\nMaintenance of the ventilation system shall be incorporated in the PMS system as per manufacturer’s recommendation.\nAn operation manual should be supplied and should include a plan of the ventilation system, showing fans, air supply and\nexhaust air openings and doors, ramps, hatches, etc.\nThe location of the control panel for the ro-ro cargo space ventilation system should also be marked. The plan should show\nthe various options for operation of the ventilation system. It should include details of the air flow design and of the estimated\nnumber of different types of vehicles in the different ro-ro cargo spaces under various loading and unloading conditions.\nThe plan should be periodically revised and/or supplemented on the basis of the experience gained from the normal vehicle\nloading and unloading conditions. A number of blank drawings should therefore be kept on board. On the basis of such\nexperience, it should also be possible to draw up guidelines for the maximum number of vehicles that should be allowed to\noperate simultaneously. Whenever possible, places which are sheltered from the air flow should be indicated on the plans.\nThe operation manual should include guidance for the service and maintenance of the systems.\nShipowners and operators should consider testing the air quality in conjunction with tests of the ventilation system to ensure\nproper maintenance and functioning of the ventilation system. Situations which indicate the necessity to conduct air-quality\nmonitoring include worker complaints (e.g. headache, dizziness, stinging of the eyes or respiratory system), indications that the\nventilation system itself has deteriorated, and changes in vessel operation which are substantially different from that for which\nthe original ventilation system was verified.\n(MSC.1/Circ.1515, Revised design guidelines and operational recommendations for\nventilation systems in ro-ro cargo spaces, 2015)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.29","internal_question_no":"08C.029","question_sort_key":8302900.279,"question_text":"Is the ro-ro ship fitted with an automatic system to control air quality in the cargo holds and are records of inspection, testing, calibration, and maintenance of the system being maintained?","guide_to_inspection":"Ro-ro ships to be fitted with an automated system to control air quality in ro-ro cargo holds by analysing the hold atmosphere\nand varying the ventilation rate accordingly. The air-quality control system should comply with the revised design guidelines and\noperational recommendations for ventilation systems in ro-ro cargo spaces contained in MSC.1/Circ.1515.\nInspection, maintenance, and repairs should be carried out in a professional manner. Owners should ensure that this is done and\nthat the necessary skills, equipment and spares are available.\nAnnual testing of the vehicle space ventilation system should be conducted by the ship’s safety delegate. Third-party testing of\nthe vehicle space ventilation system should be undertaken before entry into service of a new ship and at periodical intervals of\nfive years thereafter.\n(MSC.1/Circ.1515, Revised design guidelines and operational recommendations\nfor ventilation systems in ro-ro cargo spaces, 2015)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":145,"source_page_end":145,"raw_source_text":"Is the ro-ro ship fitted with an automatic system to control air quality in the cargo holds and are\nrecords of inspection, testing, calibration, and maintenance of the system being maintained? (V)\nGuide to Inspection\nRo-ro ships to be fitted with an automated system to control air quality in ro-ro cargo holds by analysing the hold atmosphere\nand varying the ventilation rate accordingly. The air-quality control system should comply with the revised design guidelines and\noperational recommendations for ventilation systems in ro-ro cargo spaces contained in MSC.1/Circ.1515.\nInspection, maintenance, and repairs should be carried out in a professional manner. Owners should ensure that this is done and\nthat the necessary skills, equipment and spares are available.\nAnnual testing of the vehicle space ventilation system should be conducted by the ship’s safety delegate. Third-party testing of\nthe vehicle space ventilation system should be undertaken before entry into service of a new ship and at periodical intervals of\nfive years thereafter.\n(MSC.1/Circ.1515, Revised design guidelines and operational recommendations\nfor ventilation systems in ro-ro cargo spaces, 2015)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.30","internal_question_no":"08C.030","question_sort_key":8303000.28,"question_text":"Are vehicles on the ro-ro car decks safely stowed and secured?","guide_to_inspection":"All vehicles should be secured to the ship as per the approved ship specific cargo-securing manual and the condition of\nlashings should be monitored regularly.\nBefore being accepted for shipment, vehicles should be inspected externally by a competent and responsible person or persons\nto check that they are in satisfactory condition for shipment.\nSecond-hand vehicles may be transported on top of or within other second-hand vehicles. These vehicles, carried as cargo,\nshould be subject to the same rigorous checks as other vehicles being shipped.\nLabels, placards and marks that indicates the carriage of dangerous goods should be properly displayed.\nDetails of hazardous units should be reflected on the stowage plan and the crew should be aware of the location of and be\nvigilant against the carriage of dangerous goods.\nAll vehicles should be secured to prevent movement. Contact between vehicles during a voyage may damage and rupture the\nfuel tanks or damage the electrical systems.\nVehicles should, so far as possible, be aligned in a fore and aft direction. They should not be parked on permanent walkways or\nin such a way as to obstruct fire-fighting equipment or scuppers.\nIf water spray fire curtains are installed, then vehicles should not be parked across them.\n(Ro-Ro Fires, 2017)\nBattery-powered vehicles :\n1. Risks associated with battery-powered vehicles:\n> High voltage shocks\n> Direct jet flames\n> Fires develop in intensity quickly and rapidly reach their maximum intensity (typically within 2-3 minutes)\n> Toxic gases\n> Gas explosion (if the released gas accumulates for a while before being ignited)\n> Long lasting re-ignition risk (can ignite or re-ignite weeks, or maybe months after the provoking incident)\n> Once established fires are difficult to stop/extinguish\n> Thermal runaway\n2. Thermal runway: It is a phenomenon in which the lithium-ion cell enters an uncontrollable, self-heating state.\n3. Stability checks and loading limitations:\nElectric Vehicles (EVs) are expected to be on average 25% heavier than conventional vehicles. Appropriate considerations\nshould be made in relation to loading limitations and stability calculations.\n4. I dentification of vehicles:\nThe information on the type of fuel or energy supply should be provided during booking and confirmed at the check-in if\npossible. The ship’s Operator should update in the most appropriate manner its website/booking system.\nThe crew should be able to quickly identify the type of Alternative Fuel Vehicles (AFV) based on the information provided.\nBattery Electric Vehicles (BEVs) should be clearly marked and should ideally be located in a designated area known to the crew.\nThe location should, where possible, be on weather decks, away from dangerous goods, have sufficient drainage, adequate\nseparation between vehicles for crew members wearing breathing apparatus to access from multiple access paths and be well\nclear of all emergency muster points.\n5. Conditions for carriage:\nAFVs should only be allowed onboard if they comply with the provisions of the IMDG Code as also described in1.4.3. Particular\nattention should be paid to the following:\n> If there is suspicion that the battery of EVs is damaged or their battery is defective, they should only be allowed if their\nbattery is removed\n> are free from any leakages of fuel/gases\n6. Charging onboard:\nCharging onboard ro-ro passenger ships should not be allowed unless the ship operator conducts a comprehensive risk\nassessment and approves and implements the relevant risk control measures.\nThe vessel’s manager may refer to the ALBERO project and its relevant deliverable on the requirements of charging stations\nonboard.\n7. Video monitoring:\nThe installation of closed-circuit television (CCTV) systems with flame recognition capabilities/ thermal detection properties\nwhere vehicles, including BEVs, are located can allow early detection of fires. Typically, thermal runaway can be detected at\n60-70 degrees centigrade. The position of CCTV systems should be considered. Typically, these are placed fore and aft on a\nvehicle deck. Operators should consider fitting increased numbers of CCTV cameras with thermal detection capabilities in the\nathwartship directions to enable rapid detection of thermal runaway. This also allows for the precise location of the fire to be\nidentified.\n8. Fire patrol routines:\nCrew members who conduct safety patrols of the vehicle decks should be made familiar with the early signs of thermal\nrunaway and if possible equipped with thermal handheld detectors. Early indications of thermal runaway are:\nOff-gassing. This is a release of various gases from the battery, including carbon dioxide, carbon monoxide, hydrogen, and\nvolatile organic compounds. During the early phase of gas generation, the off-gases can be heavier than air and accumulate\nat deck-level or be lighter than air and dissipate or accumulate at deck-head level if the space is not appropriately ventilated.\nOwing to the various battery chemistries, it is not possible to predict which will dominate.\nA damaged battery can create rapid heating of the battery cells. If you notice hissing, whistling, or popping, a possible sweet\nchemical smell, black “smoke” (nanoparticles of heavy metals, not smoke) or white vapour coming from the high-voltage\nbattery or the vehicle generally, assume that it is in thermal runaway and take appropriate firefighting measures. Early\nintervention will minimise the spread of any fire to adjacent vehicles.\nFire patrols should pay special attention to look for evidence of battery coolant leakage, smoke or heat from the areas of\nvehicles where a battery is normally located, for example the underside. They should also listen for “popping sounds” which\nmay be indicative of a potential thermal-runaway event.\nCrew should conduct frequent emergency drills and training in the identification and initial response to a BEV battery fire. Early\ndetection and prompt action can minimise the spread of a fire.\n(DCV Safety Alert 02/2023 – risks associated with the carriage of Battery Electric Vehicles 2023)\n(Guidance on the carriage of afvs in Ro-Ro Spaces 2022)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":146,"source_page_end":147,"raw_source_text":"Are vehicles on the ro-ro car decks safely stowed and secured? (V)\nGuide to Inspection\nAll vehicles should be secured to the ship as per the approved ship specific cargo-securing manual and the condition of\nlashings should be monitored regularly.\nBefore being accepted for shipment, vehicles should be inspected externally by a competent and responsible person or persons\nto check that they are in satisfactory condition for shipment.\nSecond-hand vehicles may be transported on top of or within other second-hand vehicles. These vehicles, carried as cargo,\nshould be subject to the same rigorous checks as other vehicles being shipped.\nLabels, placards and marks that indicates the carriage of dangerous goods should be properly displayed.\nDetails of hazardous units should be reflected on the stowage plan and the crew should be aware of the location of and be\nvigilant against the carriage of dangerous goods.\nAll vehicles should be secured to prevent movement. Contact between vehicles during a voyage may damage and rupture the\nfuel tanks or damage the electrical systems.\nVehicles should, so far as possible, be aligned in a fore and aft direction. They should not be parked on permanent walkways or\nin such a way as to obstruct fire-fighting equipment or scuppers.\nIf water spray fire curtains are installed, then vehicles should not be parked across them.\n(Ro-Ro Fires, 2017)\nBattery-powered vehicles :\n1. Risks associated with battery-powered vehicles:\n> High voltage shocks\n> Direct jet flames\n> Fires develop in intensity quickly and rapidly reach their maximum intensity (typically within 2-3 minutes)\n> Toxic gases\n> Gas explosion (if the released gas accumulates for a while before being ignited)\n> Long lasting re-ignition risk (can ignite or re-ignite weeks, or maybe months after the provoking incident)\n> Once established fires are difficult to stop/extinguish\n> Thermal runaway\n2. Thermal runway: It is a phenomenon in which the lithium-ion cell enters an uncontrollable, self-heating state.\n3. Stability checks and loading limitations:\nElectric Vehicles (EVs) are expected to be on average 25% heavier than conventional vehicles. Appropriate considerations\nshould be made in relation to loading limitations and stability calculations.\n4. I dentification of vehicles:\nThe information on the type of fuel or energy supply should be provided during booking and confirmed at the check-in if\npossible. The ship’s Operator should update in the most appropriate manner its website/booking system.\nThe crew should be able to quickly identify the type of Alternative Fuel Vehicles (AFV) based on the information provided.\nBattery Electric Vehicles (BEVs) should be clearly marked and should ideally be located in a designated area known to the crew.\nThe location should, where possible, be on weather decks, away from dangerous goods, have sufficient drainage, adequate\nseparation between vehicles for crew members wearing breathing apparatus to access from multiple access paths and be well\nclear of all emergency muster points.\n5. Conditions for carriage:\nAFVs should only be allowed onboard if they comply with the provisions of the IMDG Code as also described in1.4.3. Particular\nattention should be paid to the following:\n> If there is suspicion that the battery of EVs is damaged or their battery is defective, they should only be allowed if their\nbattery is removed\n> are free from any leakages of fuel/gases\n6. Charging onboard:\nCharging onboard ro-ro passenger ships should not be allowed unless the ship operator conducts a comprehensive risk\nassessment and approves and implements the relevant risk control measures.\nThe vessel’s manager may refer to the ALBERO project and its relevant deliverable on the requirements of charging stations\nonboard.\n7. Video monitoring:\nThe installation of closed-circuit television (CCTV) systems with flame recognition capabilities/ thermal detection properties\nwhere vehicles, including BEVs, are located can allow early detection of fires. Typically, thermal runaway can be detected at\n60-70 degrees centigrade. The position of CCTV systems should be considered. Typically, these are placed fore and aft on a\nvehicle deck. Operators should consider fitting increased numbers of CCTV cameras with thermal detection capabilities in the\nathwartship directions to enable rapid detection of thermal runaway. This also allows for the precise location of the fire to be\nidentified.\n8. Fire patrol routines:\nCrew members who conduct safety patrols of the vehicle decks should be made familiar with the early signs of thermal\nrunaway and if possible equipped with thermal handheld detectors. Early indications of thermal runaway are:\nOff-gassing. This is a release of various gases from the battery, including carbon dioxide, carbon monoxide, hydrogen, and\nvolatile organic compounds. During the early phase of gas generation, the off-gases can be heavier than air and accumulate\nat deck-level or be lighter than air and dissipate or accumulate at deck-head level if the space is not appropriately ventilated.\nOwing to the various battery chemistries, it is not possible to predict which will dominate.\nA damaged battery can create rapid heating of the battery cells. If you notice hissing, whistling, or popping, a possible sweet\nchemical smell, black “smoke” (nanoparticles of heavy metals, not smoke) or white vapour coming from the high-voltage\nbattery or the vehicle generally, assume that it is in thermal runaway and take appropriate firefighting measures. Early\nintervention will minimise the spread of any fire to adjacent vehicles.\nFire patrols should pay special attention to look for evidence of battery coolant leakage, smoke or heat from the areas of\nvehicles where a battery is normally located, for example the underside. They should also listen for “popping sounds” which\nmay be indicative of a potential thermal-runaway event.\nCrew should conduct frequent emergency drills and training in the identification and initial response to a BEV battery fire. Early\ndetection and prompt action can minimise the spread of a fire.\n(DCV Safety Alert 02/2023 – risks associated with the carriage of Battery Electric Vehicles 2023)\n(Guidance on the carriage of afvs in Ro-Ro Spaces 2022)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.31","internal_question_no":"08C.031","question_sort_key":8303100.281,"question_text":"Has the vessel been provided with procedures and contingencies with regards to fumigation of cargo holds and are the Master and Chief Officer familiar with the procedure?","guide_to_inspection":"The Master should familiarise themselves with the recommendations set out in the procedures given in the SMS manual and\nwith the guidance set out in section 3 of MSC.1/Circ.1264. In addition, some individual countries, for example the USA and\nCanada, have produced their own requirements which should be followed when fumigation is being carried out on board a ship\nwithin their territorial waters; the Master should be familiar with these requirements if appropriate.\n(Bulk Cargoes: A Guide to Good Practice, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":147,"source_page_end":147,"raw_source_text":"Has the vessel been provided with procedures and contingencies with regards to fumigation of\ncargo holds and are the Master and Chief Officer familiar with the procedure? (V)\nGuide to Inspection\nThe Master should familiarise themselves with the recommendations set out in the procedures given in the SMS manual and\nwith the guidance set out in section 3 of MSC.1/Circ.1264. In addition, some individual countries, for example the USA and\nCanada, have produced their own requirements which should be followed when fumigation is being carried out on board a ship\nwithin their territorial waters; the Master should be familiar with these requirements if appropriate.\n(Bulk Cargoes: A Guide to Good Practice, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.32","internal_question_no":"08C.032","question_sort_key":8303200.282,"question_text":"Have the air conditioning intakes for the accommodation, the engine room and other spaces been set to prevent the possibility of drawing in fumigant gas?","guide_to_inspection":"Ventilation procedures for accommodation, the engine room and other spaces should be reviewed to avoid the possibility\nof drawing fumigant gas into those spaces by incorrect ventilation. Further, it should be verified that ventilation flaps and\nclosing devices are correctly set before the fumigation is carried out and they should be maintained in the correct arrangement\nthroughout the fumigation period. A review of the ventilation regime should be completed before any ventilation of the cargo\ncompartment is started and any necessary changes to those arrangements should be made.\n(Bulk Cargoes: A Guide to Good Practice, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":147,"source_page_end":147,"raw_source_text":"Have the air conditioning intakes for the accommodation, the engine room and other spaces been\nset to prevent the possibility of drawing in fumigant gas? (V)\nGuide to Inspection\nVentilation procedures for accommodation, the engine room and other spaces should be reviewed to avoid the possibility\nof drawing fumigant gas into those spaces by incorrect ventilation. Further, it should be verified that ventilation flaps and\nclosing devices are correctly set before the fumigation is carried out and they should be maintained in the correct arrangement\nthroughout the fumigation period. A review of the ventilation regime should be completed before any ventilation of the cargo\ncompartment is started and any necessary changes to those arrangements should be made.\n(Bulk Cargoes: A Guide to Good Practice, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.33","internal_question_no":"08C.033","question_sort_key":8303300.283,"question_text":"Are necessary instruments (with spares) to determine the dew points provided, maintained in good condition and are there records of calibration of such instrument?","guide_to_inspection":"Dewpoint temperature may be measured by a variety of methods. Ships generally use a traditional wet and dry bulb arrangement\nconsisting of two identical mercury thermometers, one of which has a damp muslin wick covering the bulb. These are normally\nhoused in a protective marine screen on each bridge wing. The dewpoint temperature may then be determined by a “Dewpoint\nTable” to compare the wet and dry bulb temperatures. This figure is important when considering cargo ventilation requirements.\nWhen using traditional wet and dry bulb thermometers, the accuracy of the dew point temperature will depend on the condition\nof the equipment. The muslin covering the wet bulb should be clean, the water in the reservoir should be distilled and the bulb\nitself should be wet. In order to ensure that the readings are correct, the device should always be positioned away from any\nexhaust vents, other draughts and all sources of heat. The readings should always be taken on the windward side of the vessel.\n(Cargo Ventilation and Precautions to Minimise Sweat, 2012)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":148,"source_page_end":148,"raw_source_text":"Are necessary instruments (with spares) to determine the dew points provided, maintained in\ngood condition and are there records of calibration of such instrument? (V)\nGuide to Inspection\nDewpoint temperature may be measured by a variety of methods. Ships generally use a traditional wet and dry bulb arrangement\nconsisting of two identical mercury thermometers, one of which has a damp muslin wick covering the bulb. These are normally\nhoused in a protective marine screen on each bridge wing. The dewpoint temperature may then be determined by a “Dewpoint\nTable” to compare the wet and dry bulb temperatures. This figure is important when considering cargo ventilation requirements.\nWhen using traditional wet and dry bulb thermometers, the accuracy of the dew point temperature will depend on the condition\nof the equipment. The muslin covering the wet bulb should be clean, the water in the reservoir should be distilled and the bulb\nitself should be wet. In order to ensure that the readings are correct, the device should always be positioned away from any\nexhaust vents, other draughts and all sources of heat. The readings should always be taken on the windward side of the vessel.\n(Cargo Ventilation and Precautions to Minimise Sweat, 2012)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.34","internal_question_no":"08C.034","question_sort_key":8303400.284,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":148,"source_page_end":148,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.35","internal_question_no":"08C.035","question_sort_key":8303500.285,"question_text":"Is ventilation of cargo holds being carried out and recorded?","guide_to_inspection":"The following should be recorded on each day for each hold:\n> All temperatures taken and dew points calculated.\n> Whether or not ventilation carried out.\n> Reason for not ventilating.\n> Weather and sea condition.\n> Ventilation rule applied (e.g., three –degree rule or dew point rule)\n(Bulk Cargoes: A Guide to Good Practice, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":148,"source_page_end":148,"raw_source_text":"Is ventilation of cargo holds being carried out and recorded? (V)\nGuide to Inspection\nThe following should be recorded on each day for each hold:\n> All temperatures taken and dew points calculated.\n> Whether or not ventilation carried out.\n> Reason for not ventilating.\n> Weather and sea condition.\n> Ventilation rule applied (e.g., three –degree rule or dew point rule)\n(Bulk Cargoes: A Guide to Good Practice, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.36","internal_question_no":"08C.036","question_sort_key":8303600.286,"question_text":"Are the hold bilges cleaned prior to loading and are cleaning and checks being recorded?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":148,"source_page_end":148,"raw_source_text":"Are the hold bilges cleaned prior to loading and are cleaning and checks being recorded? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.37","internal_question_no":"08C.037","question_sort_key":8303700.287,"question_text":"Do records on board verify that cargo lights in holds were properly isolated before cargo was loaded?","guide_to_inspection":"Many bulk carrier/general cargo holds have fixed cargo lights. These can easily ignite combustible cargoes such as grain,\nanimal feed, wood chips, pulp and paper if they are too close to the light. Cargo lights in holds need to be properly isolated before\ncargo is loaded. This is best done by removing fuses or other physical links in the electrical circuits so that the lights cannot be\nswitched on by mistake.\n(Fire! A Guide to the causes and prevention of cargo fire, 2017)\nThere are certain types of cargo hold lights that can be considered safe for continuous use without posing a risk to the cargo.\nExamples include:\nLED Lights\n> Low heat emission\n> Energy-efficient and long-lasting\nFluorescent Lights\n> Generally safe for use around combustible cargo\n> Commonly used in car carriers\n> Low risk of ignition due to lower operating temperatures.\nIf such lights are installed inside the cargo hold, and there is objective evidence of regular maintenance in accordance with the\nmanufacturer’s recommendations, along with procedures in the SMS that address the requirement for isolating these lights\nbased on the type of cargo, and these procedures have been followed, then the inspector should select “Yes” as the answer to\nthis question.\nThe inspector should also record in the comments section the measures in place to ensure the safety of the cargo within the\nhold.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":148,"source_page_end":148,"raw_source_text":"Do records on board verify that cargo lights in holds were properly isolated before cargo was loaded? (V)\nGuide to Inspection\nMany bulk carrier/general cargo holds have fixed cargo lights. These can easily ignite combustible cargoes such as grain,\nanimal feed, wood chips, pulp and paper if they are too close to the light. Cargo lights in holds need to be properly isolated before\ncargo is loaded. This is best done by removing fuses or other physical links in the electrical circuits so that the lights cannot be\nswitched on by mistake.\n(Fire! A Guide to the causes and prevention of cargo fire, 2017)\nThere are certain types of cargo hold lights that can be considered safe for continuous use without posing a risk to the cargo.\nExamples include:\nLED Lights\n> Low heat emission\n> Energy-efficient and long-lasting\nFluorescent Lights\n> Generally safe for use around combustible cargo\n> Commonly used in car carriers\n> Low risk of ignition due to lower operating temperatures.\nIf such lights are installed inside the cargo hold, and there is objective evidence of regular maintenance in accordance with the\nmanufacturer’s recommendations, along with procedures in the SMS that address the requirement for isolating these lights\nbased on the type of cargo, and these procedures have been followed, then the inspector should select “Yes” as the answer to\nthis question.\nThe inspector should also record in the comments section the measures in place to ensure the safety of the cargo within the\nhold.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.38","internal_question_no":"08C.038","question_sort_key":8303800.288,"question_text":"Is an adequate record of all cargo operation activities maintained during loading and unloading?","guide_to_inspection":"The following should be recorded in the port logbook or deck logbook:\n> Starting and stopping of work at each hold, times, and dates\n> Tonnages loaded per pour into each hold and a running total loaded and in the case of unloading, tonnages offloaded per\nshift from each hold and a running total offloaded\n> Weather conditions at intervals, for example 6 hours\n> Use of ship’s cranes, if appropriate\n> Movement of shore cranes, loaders, or floating crane alongside\n> Movement of barges alongside and of floating cranes or loaders if ship is at anchor\n> Opening and closing of hatches\n> Period of precipitation\n> Draft readings\n> Any delays caused on board\n> Any delays caused ashore\n> Any surveyors attending or boarding with reason for attendance\n> Any stevedore’s damage to ship’s structure and/or fittings\n> Cargo temperature in particular for grain, seed cake and coal\n(Bulk Cargoes: A Guide to Good Practice, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":149,"source_page_end":149,"raw_source_text":"Is an adequate record of all cargo operation activities maintained during loading and unloading? (V)\nGuide to Inspection\nThe following should be recorded in the port logbook or deck logbook:\n> Starting and stopping of work at each hold, times, and dates\n> Tonnages loaded per pour into each hold and a running total loaded and in the case of unloading, tonnages offloaded per\nshift from each hold and a running total offloaded\n> Weather conditions at intervals, for example 6 hours\n> Use of ship’s cranes, if appropriate\n> Movement of shore cranes, loaders, or floating crane alongside\n> Movement of barges alongside and of floating cranes or loaders if ship is at anchor\n> Opening and closing of hatches\n> Period of precipitation\n> Draft readings\n> Any delays caused on board\n> Any delays caused ashore\n> Any surveyors attending or boarding with reason for attendance\n> Any stevedore’s damage to ship’s structure and/or fittings\n> Cargo temperature in particular for grain, seed cake and coal\n(Bulk Cargoes: A Guide to Good Practice, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.1","internal_question_no":"08D.001","question_sort_key":8400100.289,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":149,"source_page_end":149,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.2","internal_question_no":"08D.002","question_sort_key":8400200.29,"question_text":"Has appropriate cargo information been provided to the vessel prior to loading?","guide_to_inspection":"The shipper shall provide the Master or the Master’s representative with appropriate information on the cargo sufficiently in\nadvance of loading to enable the precautions which may be necessary for proper stowage and safe carriage of the cargo to be\nput into effect. Such information shall be confirmed in writing and by appropriate shipping documents prior to loading the cargo\non the ship.\nIn case of general cargo, and of cargo carried in cargo units, this information shall include a general description of the cargo,\nthe gross mass of the cargo or of the cargo units, and any relevant special properties of the cargo units. For the purpose of this\nregulation, the cargo information required in sub-chapter 1.9 of the Code of Safe Practice for Cargo Stowage and Securing,\nadopted by the Organisation by resolution A.714 (17), as may be amended, shall be provided.\nPrior to loading cargo units on board ships, the shipper shall ensure that the gross mass of such units is in accordance with the\ngross mass declared on the shipping documents.\n(SOLAS 74,2020)\nThe AMSA Information Sheet reminds ship managers about the requirements for the safe carriage of Ammonium Nitrate on\nboard ships, with particular emphasis on:\nStowage under deck in a clean cargo space capable of being opened up in an emergency.\nProtection from sources of heat.\nStowage out of direct contact with metal engine room bulkheads.\nCarriage of Ammonium Nitrate in Flexible Intermediate Bulk Containers (FIBC).\nThe full document can be accessed by clicking here.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":149,"source_page_end":149,"raw_source_text":"Has appropriate cargo information been provided to the vessel prior to loading? (V)\nGuide to Inspection\nThe shipper shall provide the Master or the Master’s representative with appropriate information on the cargo sufficiently in\nadvance of loading to enable the precautions which may be necessary for proper stowage and safe carriage of the cargo to be\nput into effect. Such information shall be confirmed in writing and by appropriate shipping documents prior to loading the cargo\non the ship.\nIn case of general cargo, and of cargo carried in cargo units, this information shall include a general description of the cargo,\nthe gross mass of the cargo or of the cargo units, and any relevant special properties of the cargo units. For the purpose of this\nregulation, the cargo information required in sub-chapter 1.9 of the Code of Safe Practice for Cargo Stowage and Securing,\nadopted by the Organisation by resolution A.714 (17), as may be amended, shall be provided.\nPrior to loading cargo units on board ships, the shipper shall ensure that the gross mass of such units is in accordance with the\ngross mass declared on the shipping documents.\n(SOLAS 74,2020)\nThe AMSA Information Sheet reminds ship managers about the requirements for the safe carriage of Ammonium Nitrate on\nboard ships, with particular emphasis on:\nStowage under deck in a clean cargo space capable of being opened up in an emergency.\nProtection from sources of heat.\nStowage out of direct contact with metal engine room bulkheads.\nCarriage of Ammonium Nitrate in Flexible Intermediate Bulk Containers (FIBC).\nThe full document can be accessed by clicking here.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.3","internal_question_no":"08D.003","question_sort_key":8400300.291,"question_text":"If dangerous goods are carried in a container, have appropriate documents been provided to the vessel, and is safety in relation to stowage of declared dangerous goods and higher risk cargoes being considered?","guide_to_inspection":"The dangerous goods transport document shall include a certification or declaration that the consignment is acceptable for transport\nand that the goods are properly packaged, marked, and labelled, and in proper condition for transport in accordance with the applicable\nregulations.\n(IMDG Code, 2018)\nEach ship carrying dangerous goods in packaged form shall have a special list or manifest setting forth, in accordance with the\nclassification set out in the IMDG Code, the dangerous goods on board and the location thereof. A detailed stowage plan, which\nidentifies by class and sets out the location of all dangerous goods on board, may be used in place of such a special list or manifest. A\ncopy of one of these documents shall be made available before departure to the person or organisation designated by the port State\nauthority.\n(SOLAS 74,2020)\nThese safety considerations include the following measures in relation to stowage of declared dangerous goods and higher risk\ncargoes:\n> Dangerous goods which cannot be extinguished by CO2 should be stowed on deck.\n> Dangerous goods which cannot be extinguished by either water or CO2 should be stowed on deck.\n> Dangerous goods prone to fire or explosion should be segregated from known ignition sources.\n> Explosives should be stowed furthest from the accommodation and primary life-saving appliances.\nThe Cargo Incident Notification System (CINS) document” Safety Considerations for Ship Operators Related to Risk-Based Stowage of\nDangerous Goods on Containerships” provides information related to safe stowage of dangerous good on container ships.\n(Safety Considerations for Ship Operators Related to Risk-Based Stowage of Dangerous Goods on Containerships, 2019)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":150,"source_page_end":150,"raw_source_text":"If dangerous goods are carried in a container, have appropriate documents been provided to the\nvessel, and is safety in relation to stowage of declared dangerous goods and higher risk cargoes\nbeing considered? (V & M)\nGuide to Inspection\nThe dangerous goods transport document shall include a certification or declaration that the consignment is acceptable for transport\nand that the goods are properly packaged, marked, and labelled, and in proper condition for transport in accordance with the applicable\nregulations.\n(IMDG Code, 2018)\nEach ship carrying dangerous goods in packaged form shall have a special list or manifest setting forth, in accordance with the\nclassification set out in the IMDG Code, the dangerous goods on board and the location thereof. A detailed stowage plan, which\nidentifies by class and sets out the location of all dangerous goods on board, may be used in place of such a special list or manifest. A\ncopy of one of these documents shall be made available before departure to the person or organisation designated by the port State\nauthority.\n(SOLAS 74,2020)\nThese safety considerations include the following measures in relation to stowage of declared dangerous goods and higher risk\ncargoes:\n> Dangerous goods which cannot be extinguished by CO2 should be stowed on deck.\n> Dangerous goods which cannot be extinguished by either water or CO2 should be stowed on deck.\n> Dangerous goods prone to fire or explosion should be segregated from known ignition sources.\n> Explosives should be stowed furthest from the accommodation and primary life-saving appliances.\nThe Cargo Incident Notification System (CINS) document” Safety Considerations for Ship Operators Related to Risk-Based Stowage of\nDangerous Goods on Containerships” provides information related to safe stowage of dangerous good on container ships.\n(Safety Considerations for Ship Operators Related to Risk-Based Stowage of Dangerous Goods on Containerships, 2019)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.4","internal_question_no":"08D.004","question_sort_key":8400400.292,"question_text":"Is there a procedure for checking the container’s seals and is there documented evidence of compliance?","guide_to_inspection":"The Master should be satisfied that the Company has in place a procedure for checking the container seals in compliance with\nthe SSP. Any irregularities should be notified immediately to the stevedores or terminal operators responsible for the loading, as\nwell as the vessel’s agent and the Company. Seals should likewise be checked at discharge to evidence that they have remained\nintact whilst on the vessel.\n(Guidance to Masters, 2006)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":150,"source_page_end":150,"raw_source_text":"Is there a procedure for checking the container’s seals and is there documented evidence of compliance? (V)\nGuide to Inspection\nThe Master should be satisfied that the Company has in place a procedure for checking the container seals in compliance with\nthe SSP. Any irregularities should be notified immediately to the stevedores or terminal operators responsible for the loading, as\nwell as the vessel’s agent and the Company. Seals should likewise be checked at discharge to evidence that they have remained\nintact whilst on the vessel.\n(Guidance to Masters, 2006)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.5","internal_question_no":"08D.005","question_sort_key":8400500.293,"question_text":"Is cargo on flat racks, where applicable properly secured?","guide_to_inspection":"If flat racks are loaded, the Master should ensure that the cargo on these units is properly lashed, secured, and protected against\nexternal elements. This includes locating a suitable stowage position to avoid damage by the impact of waves. If the Master is\nin any doubt as to whether the cargo on the flat racks is sufficiently lashed, the Master should call the Company to arrange for\na surveyor to attend and check the securing of the cargo on the flat racks. Tarpaulins, if in use, should be tight and not torn and\nneed to be checked and adjusted at regular intervals during the voyage. These checks should be recorded.\n(Guidance to Masters, 2006)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":150,"source_page_end":150,"raw_source_text":"Is cargo on flat racks, where applicable properly secured? (V)\nGuide to Inspection\nIf flat racks are loaded, the Master should ensure that the cargo on these units is properly lashed, secured, and protected against\nexternal elements. This includes locating a suitable stowage position to avoid damage by the impact of waves. If the Master is\nin any doubt as to whether the cargo on the flat racks is sufficiently lashed, the Master should call the Company to arrange for\na surveyor to attend and check the securing of the cargo on the flat racks. Tarpaulins, if in use, should be tight and not torn and\nneed to be checked and adjusted at regular intervals during the voyage. These checks should be recorded.\n(Guidance to Masters, 2006)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.6","internal_question_no":"08D.006","question_sort_key":8400600.294,"question_text":"Is the verified gross mass communicated in shipping documents sufficiently in advance to the Master?","guide_to_inspection":"The Master or Master’s representative and the terminal representative should enter into arrangements to ensure the prompt\nsharing of verified container gross mass information provided by shippers. Existing communication systems may be used for\nthe transmission and sharing of such verified container gross mass information.\nA container packed with packages and cargo items should not be loaded onto a ship to which the SOLAS regulations apply\nunless the Master or Master’s representative and the terminal representative have obtained, in advance of vessel loading, the\nverified actual gross mass of the container.\n(GUIDELINES REGARDING THE VERIFIED GROSS MASS OF A CONTAINER CARRYING CARGO, 2013)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":150,"source_page_end":150,"raw_source_text":"Is the verified gross mass communicated in shipping documents sufficiently in advance to the Master? (V)\nGuide to Inspection\nThe Master or Master’s representative and the terminal representative should enter into arrangements to ensure the prompt\nsharing of verified container gross mass information provided by shippers. Existing communication systems may be used for\nthe transmission and sharing of such verified container gross mass information.\nA container packed with packages and cargo items should not be loaded onto a ship to which the SOLAS regulations apply\nunless the Master or Master’s representative and the terminal representative have obtained, in advance of vessel loading, the\nverified actual gross mass of the container.\n(GUIDELINES REGARDING THE VERIFIED GROSS MASS OF A CONTAINER CARRYING CARGO, 2013)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.7","internal_question_no":"08D.007","question_sort_key":8400700.295,"question_text":"Have containers carried on deck or on hatch covers been stowed in the fore-and-aft direction?","guide_to_inspection":"Record a Finding if any containers were loaded in an athwartships direction.\nContainers carried on deck or on hatches of such ships should preferably be stowed in the fore-and-aft direction.\nThis stowage method is sensible regarding the interplay of stresses in rough seas and the loading capacity of containers.\nStresses in rough seas are greater athwartships than fore and aft and the loading capacity of container side walls is designed to\nbe higher than that of the end walls.\nHowever, on many ships the containers are stowed in athwartships bays or are transported athwartships for other reasons. This\nmust be taken into consideration when packing containers and securing cargo.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":151,"source_page_end":151,"raw_source_text":"Have containers carried on deck or on hatch covers been stowed in the fore-and-aft direction? (V)\nGuide to Inspection\nRecord a Finding if any containers were loaded in an athwartships direction.\nContainers carried on deck or on hatches of such ships should preferably be stowed in the fore-and-aft direction.\nThis stowage method is sensible regarding the interplay of stresses in rough seas and the loading capacity of containers.\nStresses in rough seas are greater athwartships than fore and aft and the loading capacity of container side walls is designed to\nbe higher than that of the end walls.\nHowever, on many ships the containers are stowed in athwartships bays or are transported athwartships for other reasons. This\nmust be taken into consideration when packing containers and securing cargo.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.8","internal_question_no":"08D.008","question_sort_key":8400800.296,"question_text":"Are containers stowed in block stowage?","guide_to_inspection":"Record a Finding if containers were stowed in isolated stacks, especially in outboard locations.\nGenerally, container stacks do not depend on each other for support. However, they do provide protection to each other from\nwind and waves, so stowage in isolated stacks, especially in outboard locations, should be avoided.\nMaking block stowage may be difficult for coastal container ships when limited containers are available for loading.\nThe question shall be answered YES, where isolated stowage is loaded on board a coastal container ship, provided that the\ncalculated lashing stress is within allowable range. The inspector shall record in comments if the isolated stowage is loaded on\nboard a coastal container ship.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":151,"source_page_end":151,"raw_source_text":"Are containers stowed in block stowage? (V)\nGuide to Inspection\nRecord a Finding if containers were stowed in isolated stacks, especially in outboard locations.\nGenerally, container stacks do not depend on each other for support. However, they do provide protection to each other from\nwind and waves, so stowage in isolated stacks, especially in outboard locations, should be avoided.\nMaking block stowage may be difficult for coastal container ships when limited containers are available for loading.\nThe question shall be answered YES, where isolated stowage is loaded on board a coastal container ship, provided that the\ncalculated lashing stress is within allowable range. The inspector shall record in comments if the isolated stowage is loaded on\nboard a coastal container ship.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08D","section_number":8,"section_letter":"D","section_title":"Cargo Operation - Cellular Container Ships","printed_question_no":"8.9","internal_question_no":"08D.009","question_sort_key":8400900.297,"question_text":"Are procedures for safe lashing and securing operations of containers incorporated in the ship’s SMS?","guide_to_inspection":"Procedures for safe lashing and securing operations should be included in the ship’s Safety Management System as part of the\nISM Code documentation.\n(CSS Code, 2011)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":151,"source_page_end":151,"raw_source_text":"Are procedures for safe lashing and securing operations of containers incorporated\nin the ship’s SMS? (V)\nGuide to Inspection\nProcedures for safe lashing and securing operations should be included in the ship’s Safety Management System as part of the\nISM Code documentation.\n(CSS Code, 2011)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}}]}$RISQQ91$::jsonb AS payload
),
qs AS (
  SELECT id AS question_set_id FROM public.risq_question_sets WHERE question_set_code = 'RISQ_3_2' LIMIT 1
),
input_rows AS (
  SELECT *
  FROM payload p
  CROSS JOIN LATERAL jsonb_to_recordset(p.payload->'questions') AS r(
    section_code text,
    section_number integer,
    section_letter text,
    section_title text,
    printed_question_no text,
    internal_question_no text,
    question_sort_key numeric,
    question_text text,
    guide_to_inspection text,
    answer_type text,
    answer_options jsonb,
    answer_options_inferred boolean,
    inspection_marker text,
    is_removed_question boolean,
    is_active boolean,
    guide_status text,
    source_page_start integer,
    source_page_end integer,
    raw_source_text text,
    metadata jsonb
  )
),
section_lookup AS (
  SELECT s.id AS section_id, s.question_set_id, s.section_code
  FROM public.risq_sections s
  JOIN qs ON qs.question_set_id = s.question_set_id
)
INSERT INTO public.risq_questions (
  question_set_id,
  section_id,
  section_code,
  section_number,
  section_letter,
  section_title,
  printed_question_no,
  internal_question_no,
  question_sort_key,
  question_text,
  guide_to_inspection,
  answer_type,
  answer_options,
  answer_options_inferred,
  inspection_marker,
  is_removed_question,
  is_active,
  guide_status,
  source_page_start,
  source_page_end,
  raw_source_text,
  source_hash,
  metadata,
  created_by,
  updated_by
)
SELECT
  qs.question_set_id,
  sl.section_id,
  i.section_code,
  i.section_number,
  i.section_letter,
  i.section_title,
  i.printed_question_no,
  i.internal_question_no,
  i.question_sort_key,
  i.question_text,
  i.guide_to_inspection,
  i.answer_type,
  i.answer_options,
  COALESCE(i.answer_options_inferred, false),
  COALESCE(i.inspection_marker, ''),
  COALESCE(i.is_removed_question, false),
  COALESCE(i.is_active, true),
  i.guide_status,
  i.source_page_start,
  i.source_page_end,
  i.raw_source_text,
  md5(COALESCE(i.question_text, '') || '|' || COALESCE(i.guide_to_inspection, '') || '|' || COALESCE(i.raw_source_text, '')),
  COALESCE(i.metadata, '{}'::jsonb),
  auth.uid(),
  auth.uid()
FROM input_rows i
CROSS JOIN qs
JOIN section_lookup sl
  ON sl.question_set_id = qs.question_set_id
 AND sl.section_code = i.section_code
ON CONFLICT (question_set_id, internal_question_no)
DO UPDATE SET
  section_id = EXCLUDED.section_id,
  section_code = EXCLUDED.section_code,
  section_number = EXCLUDED.section_number,
  section_letter = EXCLUDED.section_letter,
  section_title = EXCLUDED.section_title,
  printed_question_no = EXCLUDED.printed_question_no,
  question_sort_key = EXCLUDED.question_sort_key,
  question_text = EXCLUDED.question_text,
  guide_to_inspection = EXCLUDED.guide_to_inspection,
  answer_type = EXCLUDED.answer_type,
  answer_options = EXCLUDED.answer_options,
  answer_options_inferred = EXCLUDED.answer_options_inferred,
  inspection_marker = EXCLUDED.inspection_marker,
  is_removed_question = EXCLUDED.is_removed_question,
  is_active = EXCLUDED.is_active,
  guide_status = EXCLUDED.guide_status,
  source_page_start = EXCLUDED.source_page_start,
  source_page_end = EXCLUDED.source_page_end,
  raw_source_text = EXCLUDED.raw_source_text,
  source_hash = EXCLUDED.source_hash,
  metadata = EXCLUDED.metadata,
  updated_by = auth.uid();

COMMIT;

SELECT
  'RISQ question chunk 9/15 imported.' AS result,
  '08C.006' AS chunk_first_question,
  '08D.009' AS chunk_last_question,
  (SELECT COUNT(*) FROM public.risq_questions q JOIN public.risq_question_sets qs ON qs.id = q.question_set_id WHERE qs.question_set_code = 'RISQ_3_2') AS total_questions_imported_so_far;
